package com.aimall.server.ai.dto;
import jakarta.validation.constraints.*; import java.util.*;
public record KnowledgeChunkPayload(@NotBlank @Size(max=255) String chunkKey,@Size(max=32) String chunkType,@Min(1) Integer chunkNo,@Size(max=500) String title,@Size(max=500) String sectionTitle,@Size(max=2000) String sectionPath,@NotBlank @Size(max=200000) String originalContent,@NotBlank @Size(max=200000) String maskedContent,@NotBlank @Size(max=200000) String indexContent,@Size(max=2000) String snippet,@Min(1) Integer tokenCount,@NotBlank @Pattern(regexp="[a-fA-F0-9]{32,128}") String contentHash,@Pattern(regexp="[a-fA-F0-9]{32,128}") String chunkHash,@Min(1) Integer pageStart,@Min(1) Integer pageEnd){public Map<String,Object>toMap(){Map<String,Object>v=new LinkedHashMap<>();v.put("chunkKey",chunkKey);v.put("chunkType",chunkType);v.put("chunkNo",chunkNo);v.put("title",title);v.put("sectionTitle",sectionTitle);v.put("sectionPath",sectionPath);v.put("originalContent",originalContent);v.put("maskedContent",maskedContent);v.put("indexContent",indexContent);v.put("snippet",snippet);v.put("tokenCount",tokenCount);v.put("contentHash",contentHash);v.put("chunkHash",chunkHash);v.put("pageStart",pageStart);v.put("pageEnd",pageEnd);return v;}}
